            ['category' => 'interview', 'question' => 'What should I expect during the SWAP interview?', 'answer' => 'The interview is a 15-30 minute session with a DSA staff member. You will be asked about your financial situation, academic performance, and motivation for joining SWAP. Please bring original copies of your submitted documents.', 'keywords' => ['interview', 'prepare', 'expect', 'question', 'bring', 'documents'], 'sort_order' => 11],
            ['category' => 'interview', 'question' => 'Can I reschedule my interview?', 'answer' => 'If you cannot attend your scheduled interview, please contact the DSA Office immediately at dsaoffice@msu-marawi.edu.ph or visit the office. Late rescheduling may result in application forfeiture.', 'keywords' => ['reschedule', 'change', 'interview', 'date', 'cancel'], 'sort_order' => 12],

            // ── How the SWAP Portal system works ──────────────────────────────
            ['category' => 'system', 'question' => 'How does the SWAP Portal system work?', 'answer' => 'The SWAP Portal manages the whole assistantship online: you apply and upload documents, the DSA reviews and interviews you, and once approved you render service hours at your assigned office. You clock in and out using your office QR code with GPS location verification, submit a short narrative report each session, and your supervisor verifies your hours. Your stipend is released once your required hours are verified.', 'keywords' => ['system', 'works', 'portal', 'overview', 'about', 'process'], 'sort_order' => 13],
            ['category' => 'system', 'question' => 'How do I clock in for attendance?', 'answer' => 'Go to the Attendance page, make sure your phone location is enabled, then scan or paste your assigned office QR code and tap Clock In. You must be physically on the office premises — the system checks your GPS location against the office geofence, so clock-ins from outside are rejected.', 'keywords' => ['clock', 'attendance', 'scan', 'geofence', 'premises', 'timein'], 'sort_order' => 14],
