            ['category' => 'system', 'question' => 'What is a narrative report?', 'answer' => 'A narrative report is a short summary of what you did during a work session — the tasks you accomplished and any challenges. You submit it when you clock out, and your supervisor reads it when verifying your hours.', 'keywords' => ['narrative', 'report', 'summary', 'session', 'tasks'], 'sort_order' => 17],
            ['category' => 'system', 'question' => 'How do I see my rendered hours and progress?', 'answer' => 'Open the Hours page to see your verified, pending, and remaining hours toward your semester requirement, shown as a progress bar. The Reports section lets you view weekly, monthly, and semester breakdowns.', 'keywords' => ['hours', 'progress', 'rendered', 'remaining', 'track'], 'sort_order' => 18],
            ['category' => 'system', 'question' => 'How do I check my application status?', 'answer' => 'Log in and open your Dashboard. Your application status (submitted, under review, interview scheduled, approved, or rejected) is shown there, and you also receive a notification whenever it changes.', 'keywords' => ['status', 'dashboard', 'check', 'application', 'progress'], 'sort_order' => 19],
            ['category' => 'system', 'question' => 'What are the roles in the SWAP Portal?', 'answer' => 'There are four roles: Applicants apply to the program; Recipients are approved students who render service hours; Supervisors verify the hours of students in their office; and Admins (DSA) manage applications, interviews, assignments, offices, and stipends.', 'keywords' => ['roles', 'applicant', 'recipient', 'supervisor', 'admin'], 'sort_order' => 20],
            ['category' => 'system', 'question' => 'How does my supervisor verify my hours?', 'answer' => 'After you clock out, your log goes to your office supervisor as pending. They review your time and narrative report, then verify or reject it with feedback. Only verified hours count toward your requirement and stipend.', 'keywords' => ['verify', 'verification', 'supervisor', 'approve', 'pending'], 'sort_order' => 21],
            ['category' => 'system', 'question' => 'What happens if I forget to clock out?', 'answer' => 'If you leave the office geofence, the system automatically clocks you out after a short grace period. If a session is left open too long, the system also closes it automatically. Still, always try to clock out properly so your hours and narrative are accurate.', 'keywords' => ['forget', 'forgot', 'clockout', 'auto', 'open'], 'sort_order' => 22],
            ['category' => 'system', 'question' => 'How do I update my profile or change my password?', 'answer' => 'Open the Profile page from the sidebar or the avatar in the top bar. There you can update your information and change your password.', 'keywords' => ['profile', 'password', 'update', 'account', 'change'], 'sort_order' => 23],
